<template>
  <view class="p-4">
    <!-- 筛选栏 (使用 u-picker 替代 dropdown) -->
    <view class="mb-3">
      <u-button size="mini" plain @click="showRegionPicker = true">
        {{ selectedRegionText }} <u-icon name="arrow-down" size="12"></u-icon>
      </u-button>
    </view>
    
    <u-picker
      :show="showRegionPicker"
      :columns="[regionOptions]"
      keyName="text"
      @confirm="onRegionConfirm"
      @cancel="showRegionPicker = false"
      @close="showRegionPicker = false"
    ></u-picker>

    <!-- 加载状态 -->
    <view v-if="loading" class="mt-4 flex justify-center items-center">
      <u-loading-icon mode="circle"></u-loading-icon>
      <text class="ml-2 text-gray-500">加载中...</text>
    </view>

    <!-- 政策列表 -->
    <view v-else>
      <u-cell-group class="mt-3">
        <u-cell
          v-for="item in list"
          :key="item.id"
          :title="item.title"
          :label="item.region + ' · ' + item.date"
          is-link
          @click="open(item)"
        >
          <template #value>
            <u-tag text="政策" type="primary" size="mini"></u-tag>
          </template>
        </u-cell>
      </u-cell-group>

      <!-- 空状态 -->
      <u-empty v-if="list.length === 0" mode="data" text="暂无政策解读"></u-empty>

      <!-- 加载更多 -->
      <u-loadmore 
        :status="loadStatus" 
        :loading-text="'加载中...'"
        :loadmore-text="'上拉加载更多'"
        :nomore-text="'没有更多了'"
        @loadmore="onLoadMore"
      />
    </view>

    <!-- 下载资料 -->
    <view class="mt-4 text-center">
      <u-button type="primary" @click="downloadMaterials" :loading="downloading">
        下载医保报销流程图解
      </u-button>
    </view>
  </view>
</template>

<script setup lang="ts">
import { ref, onMounted, computed } from 'vue'
import request from '@/utils/request'

// 筛选条件
const region = ref('all')
const showRegionPicker = ref(false)

// 分页
const currentPage = ref(1)
const pageSize = ref(10)
const total = ref(0)
const loadStatus = ref<'loading' | 'loadmore' | 'nomore'>('loadmore')

// 筛选项
const regionOptions = ref<{ text: string; value: string }[]>([])

// 列表数据
const list = ref<any[]>([])
const loading = ref(false)
const downloading = ref(false)

const selectedRegionText = computed(() => {
  const opt = regionOptions.value.find(r => r.value === region.value)
  return opt ? opt.text : '全部地区'
})

// 获取地区选项
const fetchRegions = async () => {
  try {
    const res = await request.get('/api/resource/charity/policies/regions')
    const data = res.data || res.data || {}

    if (data.regions && Array.isArray(data.regions)) {
      regionOptions.value = [
        { text: '全部地区', value: 'all' },
        ...data.regions.map((item: any) => ({
          text: item.text || item.name,
          value: item.value || item.code
        }))
      ]
    }
  } catch (error) {
    uni.__f__('error','at pages/resource/charity/PolicyList.vue:107','获取地区选项失败:', error)
    regionOptions.value = [
      { text: '全部地区', value: 'all' },
      { text: '全国', value: 'all' },
      { text: '北京', value: 'bj' },
      { text: '上海', value: 'sh' }
    ]
  }
}

const fetchPolicies = async (isRefresh = false) => {
  if (isRefresh) {
    currentPage.value = 1
    list.value = []
  }
  
  if (loadStatus.value === 'nomore' && !isRefresh) return

  loading.value = true
  loadStatus.value = 'loading'

  try {
    const res = await request.get('/api/resource/charity/policies', {
      params: {
        region: region.value === 'all' ? undefined : region.value,
        page: currentPage.value,
        limit: pageSize.value
      }
    })
    
    const records = res.data.records || res.data.list || []
    list.value.push(...records)
    
    if (records.length < pageSize.value) {
      loadStatus.value = 'nomore'
    } else {
      loadStatus.value = 'loadmore'
      currentPage.value++
    }
  } catch (error) {
    uni.__f__('error','at pages/resource/charity/PolicyList.vue:147','获取政策失败:', error)
    loadStatus.value = 'loadmore'
    uni.showToast({ title: '加载失败，请重试', icon: 'none' })
  } finally {
    loading.value = false
  }
}

const onRegionConfirm = (e: any) => {
  const selected = e.value[0]
  region.value = selected.value
  showRegionPicker.value = false
  fetchPolicies(true)
}

const onLoadMore = () => {
  fetchPolicies()
}

const open = (item: any) => {
  uni.navigateTo({
    url: `/pages/resource/charity/PolicyDetail?id=${item.id}`
  })
}

const downloadMaterials = async () => {
  downloading.value = true
  try {
    // 模拟下载
    await new Promise(resolve => setTimeout(resolve, 1000))
    uni.showToast({ title: '下载已开始', icon: 'success' })
  } catch (error) {
    uni.showToast({ title: '下载失败', icon: 'none' })
  } finally {
    downloading.value = false
  }
}

onMounted(() => {
  fetchRegions()
  fetchPolicies()
})
</script>

